module top_module(
  input reset,
  input clk,
  output rst_sync
);parameter n = 2; // number of cycles that reset must be stable

reg [1:0] obf_sync_reset; // two-stage synchronizer

always @(posedge clk) begin
  obf_sync_reset[0] <= reset;
  obf_sync_reset[1] <= obf_sync_reset[0];
end

assign rst_sync = obf_sync_reset[1];

endmodule
